                        if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForResourcePolicy] & RequiredBitForResourcePolicy) == 0)
                        {
                            context.EvaluatedKeywordForProperty(false, 7, RequiredPropertyResourcePolicyNotPresent, "resourcePolicy"u8, "required"u8);
                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 7, RequiredPropertyResourcePolicyPresent, "resourcePolicy"u8, "required"u8);
                        }

                        if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForStateHints] & RequiredBitForStateHints) == 0)
                        {
                            context.EvaluatedKeywordForProperty(false, 8, RequiredPropertyStateHintsNotPresent, "stateHints"u8, "required"u8);
                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 8, RequiredPropertyStateHintsPresent, "stateHints"u8, "required"u8);
                        }

                        if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForValidationProfile] & RequiredBitForValidationProfile) == 0)
                        {
                            context.EvaluatedKeywordForProperty(false, 9, RequiredPropertyValidationProfileNotPresent, "validationProfile"u8, "required"u8);
                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 9, RequiredPropertyValidationProfilePresent, "validationProfile"u8, "required"u8);
                        }
                    }
                }
            }

            internal static bool Evaluate(
                IJsonDocument parentDocument,
                int parentIndex,
                IJsonSchemaResultsCollector? resultsCollector = null)
            {
                JsonSchemaContext context = JsonSchemaContext.BeginContext(
                parentDocument,
                parentIndex,
                usingEvaluatedItems: false,
                usingEvaluatedProperties: true,
                resultsCollector: resultsCollector);
                try
                {
                    Evaluate(parentDocument, parentIndex, ref context);
                    context.EndContext();
                    return context.IsMatch;
                }
                finally
                {
                    context.Dispose();
                }
            }

